#include <numeric>
#include <bits/stdc++.h>
using namespace std;

class Solution {
public:
    int longestCommonSubstring(string s1, string s2) {
        int m = s1.size(), n = s2.size();
        vector<vector<int>> dp(m + 1, vector<int>(n + 1, 0));
        int max_length = 0;
        for (int i = 1; i <= m; i++) {
            for (int j = 1; j <= n; j++) {
                if (s1[i - 1] == s2[j - 1]) {
                    dp[i][j] = dp[i - 1][j - 1] + 1;
                    max_length = max(max_length, dp[i][j]);
                }
            }
        }
        return max_length;
    }
};

int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);
    int n;
    if (!(cin >> n)) return 0;
    string s1, s2;
    cin >> s1 >> s2;
    Solution sol;
    int ans = sol.longestCommonSubstring(s1, s2);
    cout << "1" << "\n";
    cout << ans << "\n";
    return 0;
}
